// default to true, if no user defined, then need to allow until user set
var allow = true;
var userId = current.getValue("u_user");
gs.info("RJ - testing - delete - userId: " + userId);
if(userId && userId != ""){
	allow = new Organization_uiAction().canDeleteOOO(userId);
	gs.info("RJ - testing - delete - allow: " + allow);
}
answer = allow;
